// Minimal navigator/window shim for @capacitor/device to run in Node
globalThis.window = {
  navigator: {
    userAgent: 'Node.js'
  }
};
globalThis.navigator = globalThis.window.navigator;

async function run() {
  const info = await Device.getInfo();
  const id = await Device.getId();
  const battery = await Device.getBatteryInfo();

  const payload = {
    info,
    id,
    battery
  };

  console.log(JSON.stringify(payload));
}

run().catch(err => {
  console.error(err);
  process.exit(1);
});

